    energy_availability: classifyEnergyAvailability(input),
    protein_adequacy: classifyProteinAdequacy(input),
    adherence_confidence: {
      value: consistency === "high" ? "high" : consistency === "low" ? "low" : consistency === "moderate" ? "moderate" : "unknown",
      reason_codes: consistency ? ["RECENT_CONSISTENCY_REPORTED"] : ["RECENT_CONSISTENCY_MISSING"],
      source_fields: consistency ? ["training_history.consistency_last_12_weeks"] : [],
      confidence: consistency ? "high" : "low"
    },
    sport_interference_risk: sportInterference,
