    activity_name: isHiitFinisher ? `${CONDITIONING_MODALITIES[modality].display_name} HIIT Finisher` : `${CONDITIONING_MODALITIES[modality].display_name} Finisher`,
    purpose: isHiitFinisher ? "High-intensity interval finisher to maximise post-session energy expenditure." : "Utilise remaining session time for supplemental energy expenditure.",
