var OpenAIProgrammeRefinementProvider = class {
  constructor(client, config3) {
    this.client = client;
    this.config = config3;
  }
  async proposeRefinement(input, context) {
    if (!this.config.openaiModel) {
      throw refinementError(
        "OPENAI_CONFIGURATION_MISSING",
        "OpenAI model configuration is missing."
      );
    }
    try {
      const response = await this.client.responses.parse({
        model: this.config.openaiModel,
        input: [
          { role: "system", content: refinementSystemPrompt },
          {
            role: "user",
            content: JSON.stringify({
              refinement_context: input,
              retry_feedback: context.retryFeedback ?? null
            })
          }
        ],
        text: {
          format: zodTextFormat(
            ProgrammeRefinementProposalSchema,
            "programme_refinement"
          )
        },
        max_output_tokens: 4e3
      });
      for (const output of response.output) {
        if (output.type !== "message") continue;
        for (const item2 of output.content) {
          if (item2.type === "refusal") {
            throw refinementError(
              "LLM_PROVIDER_REFUSAL",
              "The refinement provider declined the request."
            );
          }
          if (item2.type === "output_text" && item2.parsed) {
            const parsed = ProgrammeRefinementProposalSchema.safeParse(
              item2.parsed
            );
            if (!parsed.success) {
              throw refinementError(
                "LLM_OUTPUT_INVALID",
                "The refinement provider returned invalid structured output."
              );
            }
            return {
              proposal: parsed.data,
              provider: "openai",
              model: this.config.openaiModel,
              responseId: response.id ?? null,
              usage: {
                inputTokens: response.usage?.input_tokens ?? null,
                outputTokens: response.usage?.output_tokens ?? null
              }
            };
          }
        }
      }
      throw refinementError(
        "LLM_OUTPUT_INVALID",
        "The refinement provider returned no structured proposal."
      );
    } catch (error2) {
      if (error2 instanceof Error && "code" in error2 && typeof error2.code === "string" && error2.code.startsWith("LLM_")) {
        throw error2;
      }
      if (error2 instanceof Error && (error2.name.includes("Timeout") || error2.message.includes("timed out"))) {
        throw refinementError(
          "LLM_PROVIDER_TIMEOUT",
          "The refinement provider timed out."
        );
      }
      throw refinementError(
        "LLM_PROVIDER_ERROR",
        "The refinement provider is unavailable."
      );
    }
  }
};

